import React from "react";

const demos = [
  {
    id: "aria",
    tag: "Local AI Assistant",
    name: "ARIA — Local AI Assistant",
    description:
      "A fully local agentic AI assistant that runs entirely on-device. No cloud, no data leaving your machine. ARIA uses tools, manages tasks, and acts autonomously — built to show what agentic AI looks like when privacy is non-negotiable."
  },
  {
    id: "car-finder",
    tag: "Decision Engine",
    name: "Used Car Evaluator",
    description:
      "Feed it your budget and preferences, then give it cars via web search, screenshots, or manual entry. It returns scored cards with km/year calculations, market valuations, deal classifications, and a suggested opening offer with negotiation range. A decision engine, not a search engine."
  },
  {
    id: "abm",
    tag: "Sales Automation",
    name: "B2B Lead Targeting Agent",
    description:
      "Takes your ideal customer persona, builds lookalikes, queries Apollo via API, and pushes qualified leads directly to your CRM. Full account-based marketing pipeline with zero manual steps."
  },
  {
    id: "qr",
    tag: "Marketing Tool",
    name: "Smart QR Code Generator",
    description:
      "Generates custom-designed QR codes with built-in UTM tracking. Works globally, supports multiple campaigns, and gives you clean attribution data every time someone scans."
  }
];

function FlipCard({ tag, name, description }) {
  return (
    <div
      className="flip-card"
      style={{ height: "320px", perspective: "1000px" }}
    >
      <div className="flip-card-inner">
        {/* Front — screenshot placeholder */}
        <div
          className="flip-card-front card"
          style={{
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            gap: "1rem",
            position: "relative",
            overflow: "hidden"
          }}
        >
          {/* Grid pattern */}
          <div
            aria-hidden="true"
            style={{
              position: "absolute",
              inset: 0,
              backgroundImage:
                "linear-gradient(#252A40 1px, transparent 1px), linear-gradient(90deg, #252A40 1px, transparent 1px)",
              backgroundSize: "32px 32px",
              opacity: 0.4
            }}
          />

          {/* Tag */}
          <p
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: "0.6rem",
              letterSpacing: "0.14em",
              textTransform: "uppercase",
              color: "#5B8DEF",
              background: "rgba(91, 141, 239, 0.08)",
              border: "1px solid rgba(91, 141, 239, 0.2)",
              padding: "0.2rem 0.6rem",
              borderRadius: "0.25rem",
              zIndex: 1
            }}
          >
            {tag}
          </p>

          {/* Name */}
          <h3
            style={{
              fontFamily: "'Space Grotesk', sans-serif",
              fontWeight: 700,
              fontSize: "1.4rem",
              color: "#F0F0EC",
              letterSpacing: "-0.02em",
              zIndex: 1,
              textAlign: "center"
            }}
          >
            {name}
          </h3>

          {/* Screenshot placeholder label */}
          <p
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: "0.6rem",
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "#3A3A5E",
              zIndex: 1
            }}
          >
            Screenshot coming
          </p>

          {/* Hover hint */}
          <p
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: "0.6rem",
              letterSpacing: "0.08em",
              color: "#5B8DEF",
              opacity: 0.6,
              zIndex: 1,
              position: "absolute",
              bottom: "1rem"
            }}
          >
            Hover to learn more
          </p>
        </div>

        {/* Back — description */}
        <div
          className="flip-card-back card"
          style={{
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            padding: "2rem",
            background: "#1A1D2E",
            borderColor: "rgba(91, 141, 239, 0.25)"
          }}
        >
          <p
            className="eyebrow"
            style={{ marginBottom: "0.75rem" }}
          >
            {tag}
          </p>
          <h3
            style={{
              fontFamily: "'Space Grotesk', sans-serif",
              fontWeight: 700,
              fontSize: "1.2rem",
              color: "#F0F0EC",
              letterSpacing: "-0.02em",
              marginBottom: "1rem"
            }}
          >
            {name}
          </h3>
          <p
            style={{
              fontFamily: "'Inter', sans-serif",
              fontSize: "0.875rem",
              color: "#C8C8DC",
              lineHeight: 1.7
            }}
          >
            {description}
          </p>
        </div>
      </div>

      <style>{`
        .flip-card {
          cursor: pointer;
        }
        .flip-card-inner {
          position: relative;
          width: 100%;
          height: 100%;
          transition: transform 0.55s cubic-bezier(0.4, 0, 0.2, 1);
          transform-style: preserve-3d;
        }
        .flip-card:hover .flip-card-inner {
          transform: rotateY(180deg);
        }
        .flip-card-front,
        .flip-card-back {
          position: absolute;
          width: 100%;
          height: 100%;
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
          border-radius: 0.75rem;
        }
        .flip-card-back {
          transform: rotateY(180deg);
        }
        @media (prefers-reduced-motion: reduce) {
          .flip-card-inner {
            transition: none;
          }
        }
      `}</style>
    </div>
  );
}

export default function Demos() {
  return (
    <section
      id="demos"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40",
        scrollMarginTop: "70px"
      }}
    >
      {/* Header */}
      <div className="mb-14" style={{ maxWidth: "44ch" }}>
        <p className="eyebrow mb-4">Demos</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.6rem, 3.5vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1
          }}
        >
          Don't believe me?<br />
          <span style={{ color: "#5B8DEF" }}>See for yourself.</span>
        </h2>
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "1rem",
            color: "#C8C8DC",
            marginTop: "1rem",
            lineHeight: 1.7
          }}
        >
          Real systems I've built. Hover each card to see what it does.
        </p>
      </div>

      {/* Flip cards grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 280px), 1fr))",
          gap: "1.25rem"
        }}
      >
        {demos.map((demo) => (
          <FlipCard key={demo.id} {...demo} />
        ))}
      </div>
    </section>
  );
}
